import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Css/Landing.css';

const Landing = () => {
  const navigate = useNavigate();
  const [games, setGames] = useState([]);
  const [showProfile, setShowProfile] = useState(false);

  // Fetch games from PostgreSQL (as before)
  useEffect(() => {
    const fetchGames = async () => {
      try {
        const response = await fetch('http://localhost:8000/api/top-games');
        const data = await response.json();
        if (data.status === 'success') {
          setGames(data.games);
        }
      } catch (error) {
        console.error("Database connection failed", error);
      }
    };
    fetchGames();
  }, []);

  const handleLogout = () => {
    navigate('/');
  };

  const handleWishlist = (gameTitle) => {
    alert(`Wishlist function for ${gameTitle} is next!`);
  };

  return (
    <div className="landing-shield">
      {/* HEADER */}
      <header className="dash-header">
        <div className="logo">GAMING<span>HUB</span></div>
        <nav className="dash-nav">
          <span className="active">Home</span>
          <span>Community</span>
        </nav>
        <div className="search-bar">
          <input type="text" placeholder="Search games..." />
        </div>
        <div className="profile-wrapper" onClick={() => setShowProfile(!showProfile)}>
          <div className="avatar">G</div>
          {/* Dropdown */}
          {showProfile && (
            <div className="profile-dropdown">
              <div className="dropdown-item">Profile</div>
              <div className="dropdown-item logout" onClick={handleLogout}>Logout</div>
            </div>
          )}
        </div>
      </header>

      {/* --- ASYMMETRIC SPLIT HERO (Adapted from ref image) --- */}
      <section className="hero-split">
        <div className="hero-left">
          <h1>Level Up<br/>Your Hub</h1>
          <p>Find. Play. Connect. The Grid is yours.</p>
          <div className="hero-details">
            <div className="detail-item">
              <span className="detail-num">#01</span>
              <div>
                <strong>Discover Games</strong>
                <p>Find your next play from millions.</p>
              </div>
            </div>
            <div className="detail-item">
              <span className="detail-num">#02</span>
              <div>
                <strong>Track Stats</strong>
                <p>Log your hours, achievements, and progress.</p>
              </div>
            </div>
          </div>
        </div>
        <div className="hero-right">
          <img 
            src="https://images.unsplash.com/photo-1542751371-adc38448a05e?q=80&w=1000" 
            alt="Gaming visual" 
            className="hero-image"
          />
        </div>
      </section>

      {/* GAMES GRID */}
      <section className="games-section">
        <div className="games-grid">
          {games.map((game) => (
            <div key={game.id} className="game-card">
              <img src={game.image} alt={game.title} className="game-img" />
              <div className="game-info">
                <div>
                  <h3>{game.title}</h3>
                  <span className="genre-badge">{game.genre}</span>
                </div>
                {/* Wishlist Button */}
                <button className="heart-btn" onClick={() => handleWishlist(game.title)}>
                  ♥
                </button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* FOOTER - With Social Icons from ref image */}
      <footer className="dash-footer">
        <div className="social-icons">
          <div className="icon-circle">f</div>
          <div className="icon-circle">t</div>
          <div className="icon-circle">in</div>
          <div className="icon-circle">ig</div>
        </div>
        <div className="footer-switch">
          Don't have an account? <span>Sign up</span>
        </div>
      </footer>
    </div>
  );
};

export default Landing;
